const svg = $('#hp-svg'), sig = $('#hp-sig'), sigv = $('#hp-sigv');
const W = 620, H = 260, pad = 40;
const xmin = -2.5, xmax = 3.5, ymin = -2.5, ymax = 2.5;
const toX = x => pad + (x-xmin)/(xmax-xmin)*(W-2*pad);
const toY = y => H - pad - (y-ymin)/(ymax-ymin)*(H-2*pad);

function draw(){
  svg.innerHTML = '';
  const sv = parseFloat(sig.value);
  // green half-plane (right of sv)
  const xL = toX(sv), xR = toX(xmax);
  svg.appendChild(SVG('rect',{x:xL,y:toY(ymax),width:xR-xL,height:toY(ymin)-toY(ymax),
    fill:'rgba(131,193,103,0.18)'}));
  // red half-plane (left of sv)
  svg.appendChild(SVG('rect',{x:toX(xmin),y:toY(ymax),width:xL-toX(xmin),height:toY(ymin)-toY(ymax),
    fill:'rgba(224,122,95,0.15)'}));
  // axes
  svg.appendChild(SVG('line',{x1:toX(xmin),y1:toY(0),x2:toX(xmax),y2:toY(0),stroke:'var(--mute)','stroke-width':1}));
  svg.appendChild(SVG('line',{x1:toX(0),y1:toY(ymin),x2:toX(0),y2:toY(ymax),stroke:'var(--mute)','stroke-width':1}));
  // grid ticks
  for(let k=-2;k<=3;k++){
    svg.appendChild(SVG('line',{x1:toX(k),y1:toY(0)-4,x2:toX(k),y2:toY(0)+4,stroke:'var(--mute)'}));
    const t = SVG('text',{x:toX(k),y:toY(0)+18,'text-anchor':'middle','font-size':11,fill:'var(--mute)'});
    t.textContent = k; svg.appendChild(t);
  }
  // boundary
  svg.appendChild(SVG('line',{x1:toX(sv),y1:toY(ymin),x2:toX(sv),y2:toY(ymax),
    stroke:'var(--yellow)','stroke-width':2,'stroke-dasharray':'4 4'}));
  // labels
  const lbl1 = SVG('text',{x:toX(sv)+6,y:toY(ymax)+14,'font-size':12,fill:'var(--yellow)'});
  lbl1.textContent = 'Re s = σₐ';
  svg.appendChild(lbl1);
  const lbl2 = SVG('text',{x:toX(2.6),y:toY(ymax)+14,'font-size':12,fill:'var(--green)'});
  lbl2.textContent = 'absolute convergence';
  svg.appendChild(lbl2);
  const lbl3 = SVG('text',{x:toX(-2.3),y:toY(ymax)+14,'font-size':12,fill:'var(--pink)'});
  lbl3.textContent = 'divergence';
  svg.appendChild(lbl3);
  const lbl4 = SVG('text',{x:toX(xmax)-6,y:toY(0)-6,'text-anchor':'end','font-size':11,fill:'var(--mute)'});
  lbl4.textContent = 'Re s'; svg.appendChild(lbl4);
  const lbl5 = SVG('text',{x:toX(0)+6,y:toY(ymax)+14,'font-size':11,fill:'var(--mute)'});
  lbl5.textContent = 'Im s'; svg.appendChild(lbl5);
  sigv.textContent = `σₐ = ${sv.toFixed(2)}`;
}
sig.addEventListener('input', draw);
draw();

const svg = $('#hp-svg'), sig = $('#hp-sig'), sigv = $('#hp-sigv');
const W = 620, H = 260, pad = 40;
const xmin = -2.5, xmax = 3.5, ymin = -2.5, ymax = 2.5;
const toX = x => pad + (x-xmin)/(xmax-xmin)*(W-2*pad);
const toY = y => H - pad - (y-ymin)/(ymax-ymin)*(H-2*pad);

