sig.addEventListener('input', draw);
draw();

const svg = $('#z-svg'), sig = $('#z-sig'), val = $('#z-val');
const W = 620, H = 280, pad = 40;
const xmin = 1.0, xmax = 5.0, ymin = 0, ymax = 6;
const toX = x => pad + (x-xmin)/(xmax-xmin)*(W-2*pad);
const toY = y => H - pad - (y-ymin)/(ymax-ymin)*(H-2*pad);

function zeta(s){
  let S = 0; const N = 400;
  for(let n=1;n<=N;n++) S += 1/Math.pow(n,s);
  return S;
}

function draw(){
  svg.innerHTML = '';
  // axes
  svg.appendChild(SVG('line',{x1:toX(xmin),y1:toY(0),x2:toX(xmax),y2:toY(0),stroke:'var(--mute)'}));
  svg.appendChild(SVG('line',{x1:toX(xmin),y1:toY(0),x2:toX(xmin),y2:toY(ymax),stroke:'var(--mute)'}));
  // ticks
  for(let k=1;k<=5;k++){
    const t = SVG('text',{x:toX(k),y:toY(0)+18,'text-anchor':'middle','font-size':11,fill:'var(--mute)'});
    t.textContent = k; svg.appendChild(t);
  }
  for(let k=0;k<=6;k++){
    const t = SVG('text',{x:toX(xmin)-8,y:toY(k)+4,'text-anchor':'end','font-size':11,fill:'var(--mute)'});
    t.textContent = k; svg.appendChild(t);
  }
  // vertical asymptote at s=1
  svg.appendChild(SVG('line',{x1:toX(1.0),y1:toY(0),x2:toX(1.0),y2:toY(ymax),
    stroke:'var(--pink)','stroke-width':1.5,'stroke-dasharray':'3 4'}));
  const a = SVG('text',{x:toX(1.0)+6,y:toY(ymax)+14,'font-size':11,fill:'var(--pink)'});
  a.textContent = 'pole at s=1'; svg.appendChild(a);

  // curve
  let dStr = '';
  const steps = 140;
  for(let i=0;i<=steps;i++){
    const s = xmin + 0.02 + (xmax - xmin - 0.02) * i/steps;
    const y = zeta(s);
    const X = toX(s), Y = toY(Math.min(y,ymax));
    dStr += (i===0?'M':'L') + X + ' ' + Y + ' ';
  }
  svg.appendChild(SVG('path',{d:dStr,fill:'none',stroke:'var(--yellow)','stroke-width':2}));

  // marker
  const s0 = parseFloat(sig.value);
  const z = zeta(s0);
  const X = toX(s0), Y = toY(Math.min(z,ymax));
  svg.appendChild(SVG('circle',{cx:X,cy:Y,r:5,fill:'var(--blue)'}));
  const lblY = Y - 12;
  const t = SVG('text',{x:X,y:lblY,'text-anchor':'middle','font-size':12,fill:'var(--blue)'});
  t.textContent = `ζ(${s0.toFixed(2)}) ≈ ${z.toFixed(4)}`;
  svg.appendChild(t);

  val.textContent = `ζ(${s0.toFixed(2)}) ≈ ${z.toFixed(4)}    [1/(σ-1) ≈ ${(1/(s0-1)).toFixed(4)}]`;
}
sig.addEventListener('input', draw);
draw();

