const NSel = $('#ct-N'), info = $('#ct-info'), out = $('#ct-table');

function gcd(a,b){ while(b){ [a,b] = [b, a%b]; } return a; }
function units(N){
  const U = []; for(let k=1;k<N;k++) if(gcd(k,N)===1) U.push(k); return U;
}
function orderOf(g, N){
  let k = 1, x = g % N; while(x !== 1){ x = (x*g) % N; k++; if(k > N+2) return -1; }
  return k;
}
function primitiveRoot(N){
  const U = units(N), phi = U.length;
  for(const g of U){ if(orderOf(g,N) === phi) return g; }
  return null; // group is not cyclic (e.g. N=8)
}
function characters(N){
  const U = units(N), phi = U.length;
  const g = primitiveRoot(N);
  if(g !== null){
    // cyclic: χ_k sends g -> ω^k, ω = e^{2πi/phi}
    const chis = [];
    for(let k=0;k<phi;k++){
      const chi = {};
      // precompute powers of g
      let x = 1;
      for(let j=0;j<phi;j++){
        const val = {re: Math.cos(2*Math.PI*k*j/phi), im: Math.sin(2*Math.PI*k*j/phi)};
        chi[x] = val;
        x = (x*g) % N;
      }
      chis.push(chi);
    }
    return {U, chis};
  } else {
    // non-cyclic: only N=8 in our list: (Z/8)* = {1,3,5,7} = Z/2 x Z/2
    // generators 3 and 5, relations 3^2 = 1, 5^2 = 1, (3·5) mod 8 = 7
    if(N === 8){
      const chis = [];
      // chi_{a,b}(3^i · 5^j) = (-1)^{ai} · (-1)^{bj}
      const table = {1:[0,0], 3:[1,0], 5:[0,1], 7:[1,1]};
      for(let a=0;a<2;a++) for(let b=0;b<2;b++){
        const chi = {};
        for(const [u,[i,j]] of Object.entries(table)){
          const sgn = Math.pow(-1, a*i + b*j);
          chi[+u] = {re: sgn, im: 0};
        }
        chis.push(chi);
      }
      return {U, chis};
    }
    // fallback: only trivial
    const chi = {}; for(const u of U) chi[u] = {re:1,im:0};
    return {U, chis: [chi]};
  }
}

function fmt(z){
  const eps = 1e-9;
  if(Math.abs(z.im) < eps){
    if(Math.abs(z.re-1) < eps) return '1';
    if(Math.abs(z.re+1) < eps) return '−1';
    return z.re.toFixed(3);
  }
  if(Math.abs(z.re) < eps){
    if(Math.abs(z.im-1) < eps) return 'i';
    if(Math.abs(z.im+1) < eps) return '−i';
    return z.im.toFixed(3)+'i';
  }
  return `${z.re.toFixed(2)}${z.im>=0?'+':''}${z.im.toFixed(2)}i`;
}

function render(){
  const N = parseInt(NSel.value,10);
  const {U, chis} = characters(N);
  info.textContent = `|(Z/${N})×| = φ(${N}) = ${U.length},  characters: ${chis.length}`;
  let html = '<table class="plain"><thead><tr><th>n</th>';
  for(let i=0;i<chis.length;i++) html += `<th>χ<sub>${i}</sub></th>`;
  html += '</tr></thead><tbody>';
  for(const u of U){
    html += `<tr><td>${u}</td>`;
    for(const chi of chis){
      html += `<td>${fmt(chi[u])}</td>`;
    }
    html += '</tr>';
  }
  html += '</tbody></table>';
  out.innerHTML = html;
}
NSel.addEventListener('change', render);
