// Lanczos approximation for Gamma
function gamma(z){
  const g = 7;
  const c = [0.99999999999980993, 676.5203681218851, -1259.1392167224028,
             771.32342877765313, -176.61502916214059, 12.507343278686905,
             -0.13857109526572012, 9.9843695780195716e-6, 1.5056327351493116e-7];
  if(z < 0.5) return Math.PI / (Math.sin(Math.PI*z) * gamma(1-z));
  z -= 1;
  let x = c[0];
  for(let i=1;i<g+2;i++) x += c[i]/(z+i);
  const t = z + g + 0.5;
  return Math.sqrt(2*Math.PI) * Math.pow(t, z+0.5) * Math.exp(-t) * x;
}

function integrand(x, s, n){
  // x^{s-1} * e^{-n x}
  return Math.pow(x, s-1) * Math.exp(-n*x);
}

function integrate(s, n){
  // trapezoidal rule on [eps, X] with adaptive upper bound
  const eps = 1e-4;
  const X = 60 / n;           // e^{-nx} is negligible past ~60/n
  const N = 4000;
  const dx = (X - eps) / N;
  let S = 0.5 * (integrand(eps, s, n) + integrand(X, s, n));
  for(let i=1;i<N;i++) S += integrand(eps + i*dx, s, n);
  return S * dx;
}

