// partial zeta on vertical line
function zetaComplex(sigma, t, N){
  // sum_{n=1}^N n^{-sigma-it} = sum n^{-sigma} * (cos(t log n) - i sin(t log n))
  let re=0, im=0;
  for(let n=1;n<=N;n++){
    const nps = Math.pow(n, -sigma);
    const arg = t * Math.log(n);
    re += nps * Math.cos(arg);
    im -= nps * Math.sin(arg);
  }
  return {re, im};
}

// truncated Perron: (1/2π) * ∫_{-T}^{T} ζ(c+it) * x^{c+it} / (c+it) dt
// (the i's combine: ds = i dt, so 1/(2πi) ∫ = 1/(2π) ∫ after substitution)
function truncatedPerron(x, T, c, M){
  const N = 30;        // truncate ζ series
  const Ntheta = 2*M;  // number of sample points in t
  let Sre=0, Sim=0;
  const dt = (2*T)/Ntheta;
  for(let k=0;k<=Ntheta;k++){
    const t = -T + k*dt;
    // ζ(c+it) approx
    const z = zetaComplex(c, t, N);
    // x^{c+it} = x^c * (cos(t ln x) + i sin(t ln x))
    const xc = Math.pow(x, c);
    const lnx = Math.log(x);
    const xre = xc * Math.cos(t*lnx);
    const xim = xc * Math.sin(t*lnx);
    // product z * x^s
    const pre = z.re*xre - z.im*xim;
    const pim = z.re*xim + z.im*xre;
    // divide by (c+it):  1/(c+it) = (c - it)/(c^2+t^2)
    const denom = c*c + t*t;
    const dre = c/denom, dim = -t/denom;
    const qre = pre*dre - pim*dim;
    const qim = pre*dim + pim*dre;
    const w = (k===0 || k===Ntheta) ? 0.5 : 1;
    Sre += w*qre;
    Sim += w*qim;
  }
  Sre *= dt / (2*Math.PI);
  Sim *= dt / (2*Math.PI);
  return Sre;  // real part is the answer
}

function draw(){
