function sieve(N){
  const comp = new Uint8Array(N+1);
  for(let p=2;p*p<=N;p++) if(!comp[p]) for(let k=p*p;k<=N;k+=p) comp[k] = 1;
  const primes = [];
  for(let p=2;p<=N;p++) if(!comp[p]) primes.push(p);
  return primes;
}
const PRIMES = sieve(2000);

function draw(){
  svg.innerHTML = '';
  const X = parseInt(xR.value, 10);
  xv.textContent = 'x = ' + X;
