  let n1 = 0, n3 = 0;
  for(let p=2;p<=X;p++){
    if(PRIMES.indexOf(p) !== -1){
      if(p%4===1) n1++;
      else if(p%4===3) n3++;
    }
    if(p%step===0 || p===X){
      xs.push(p); c1.push(n1); c3.push(n3);
    }
  }
  const ymax = Math.max(n1, n3, 5) * 1.15;
