  }
  svg.appendChild(SVG('path',{d:d1,fill:'none',stroke:'var(--blue)','stroke-width':2}));
  svg.appendChild(SVG('path',{d:d3,fill:'none',stroke:'var(--yellow)','stroke-width':2}));
  // asymptote x/(2 log x)
  let dA = '';
  for(let i=1;i<xs.length;i++){
    const y = xs[i] / (2*Math.log(xs[i]));
    dA += (i===1?'M':'L') + toX(xs[i]) + ' ' + toY(y) + ' ';
  }
  svg.appendChild(SVG('path',{d:dA,fill:'none',stroke:'var(--green)','stroke-width':1.5,'stroke-dasharray':'5 5'}));

  // legends
  const L1 = SVG('text',{x:pad+10,y:pad+10,'font-size':12,fill:'var(--blue)'});
  L1.textContent = '— π(x; 4, 1)'; svg.appendChild(L1);
  const L2 = SVG('text',{x:pad+10,y:pad+26,'font-size':12,fill:'var(--yellow)'});
  L2.textContent = '— π(x; 4, 3)'; svg.appendChild(L2);
  const L3 = SVG('text',{x:pad+10,y:pad+42,'font-size':12,fill:'var(--green)'});
  L3.textContent = '- - x/(2 log x)'; svg.appendChild(L3);

  // ticks
  for(let k=0;k<=5;k++){
    const v = Math.round(X*k/5);
    const t = SVG('text',{x:toX(v),y:toY(0)+18,'text-anchor':'middle','font-size':11,fill:'var(--mute)'});
    t.textContent = v; svg.appendChild(t);
  }

